#include<iostream>
#include<vector>
#include<string>
#include<algorithm>
using namespace std;string R[4];int PL,NB,MB;struct S{int L[4],x,sp;vector<string>a;int nb(){int s=0;for(int i=0;i<4;i++)s+=L[i];return s;}double sc(){double b[]={.6,.2,.3,.5,.5,.1};return nb()*x+(a.size()?b["SJWUDO"[0]-a.back()[0]]:0);}};bool h0(int i,int a,int b){for(int j=a;j<b&&j<PL;j++)if(R[i][j]=='0')return 1;return 0;}S sim(S s,string act){S n=s;n.a.push_back(act);if(act=="SPEED")n.sp++;if(act=="SLOW")n.sp--;if(act=="SPEED"||act=="SLOW"||act=="WAIT"){for(int i=0;i<4;i++)if(n.L[i]&&h0(i,n.x,n.x+n.sp))n.L[i]=0;n.x+=n.sp;}else if(act=="JUMP"){for(int i=0;i<4;i++)if(n.L[i]&&(R[i][n.x]=='0'||(n.x+n.sp<PL&&R[i][n.x+n.sp]=='0')))n.L[i]=0;n.x+=n.sp;}else if(act=="UP"){if(n.L[0]){for(int i=0;i<4;i++)if(n.L[i]&&h0(i,n.x,n.x+n.sp))n.L[i]=0;}else for(int i=1;i<4;i++){if(!n.L[i-1]&&n.L[i]){if(h0(i-1,n.x,n.x+n.sp)||h0(i,n.x,n.x+n.sp))n.L[i-1]=n.L[i]=0;else{n.L[i-1]=1;n.L[i]=0;}}else if(n.L[i-1]&&n.L[i]){if(h0(i-1,n.x,n.x+n.sp))n.L[i-1]=0;if(h0(i,n.x,n.x+n.sp))n.L[i]=0;}}n.x+=n.sp;}else{if(n.L[3]){for(int i=0;i<4;i++)if(n.L[i]&&h0(i,n.x,n.x+n.sp))n.L[i]=0;}else for(int i=2;i>=0;i--){if(!n.L[i+1]&&n.L[i]){if(h0(i,n.x,n.x+n.sp)||h0(i+1,n.x,n.x+n.sp))n.L[i+1]=n.L[i]=0;else{n.L[i+1]=1;n.L[i]=0;}}else if(n.L[i+1]&&n.L[i]){if(h0(i+1,n.x,n.x+n.sp))n.L[i+1]=0;if(h0(i,n.x,n.x+n.sp))n.L[i]=0;}}n.x+=n.sp;}return n;}int main(){cin>>NB>>MB;cin.ignore();for(int i=0;i<4;i++){getline(cin,R[i]);R[i]+=string(50,'.');}PL=R[0].size();vector<string>F;string acts[]={"SPEED","JUMP","WAIT","UP","DOWN","SLOW"};for(;;){if(F.size()){int sp;cin>>sp;for(int i=0;i<NB;i++){int a,b,c;cin>>a>>b>>c;}cout<<F[0]<<"\n";F.erase(F.begin());continue;}int sp;cin>>sp;S st;st.sp=sp;st.x=0;for(int i=0;i<4;i++)st.L[i]=0;for(int i=0;i<NB;i++){int x,y,a;cin>>x>>y>>a;st.L[y]=a;if(a)st.x=x;}vector<S>q={st};S*best=0;S bs;for(int it=0;it<30&&q.size();it++){vector<S>nq;for(auto&s:q)for(auto&act:acts){S n=sim(s,act);if(n.nb()<MB||n.sp<1)continue;if(n.x>=PL-30){if(!best||n.nb()>bs.nb()){bs=n;best=&bs;}continue;}nq.push_back(n);}sort(nq.begin(),nq.end(),[](S&a,S&b){return a.sc()>b.sc();});if(nq.size()>200)nq.resize(200);q=nq;if(best)break;}F=best?bs.a:vector<string>{"SPEED"};cout<<F[0]<<"\n";F.erase(F.begin());}}